--

CREATE FUNCTION public.can_user_send_contact(user_uuid uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  limits RECORD;
BEGIN
  SELECT * INTO limits FROM get_user_contact_limits(user_uuid);
  RETURN limits.can_send_more;
END;
$$;


