--

CREATE FUNCTION public.delete_coupon(p_admin_id uuid, p_coupon_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  -- Verificar que es superadmin
  IF NOT EXISTS (
    SELECT 1 FROM users 
    WHERE id = p_admin_id AND role = 'superadmin'
  ) THEN
