  RETURN QUERY
  SELECT b.id, b.title, b.image_url, b.link_url, b.category
  FROM banners b
  WHERE b.type = p_type
    AND b.is_active = true
    AND (p_category IS NULL OR b.category = p_category OR b.category IS NULL)
