-- Name: images_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.images_stats WITH (security_invoker='on') AS
 SELECT listing_type,
    count(*) AS total_images,
    sum(
        CASE
            WHEN (is_optimized = true) THEN 1
            ELSE 0
        END) AS optimized_images,
    avg(file_size) AS avg_file_size,
    avg(optimized_size) AS avg_optimized_size,
    sum(file_size) AS total_storage_bytes,
    sum(optimized_size) AS total_optimized_storage_bytes
   FROM public.images
  GROUP BY listing_type;


--
-- Name: jobs_log; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.jobs_log (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    job_name character varying(255) NOT NULL,
    job_type character varying(100) NOT NULL,
    source_id uuid,
    status character varying(50) NOT NULL,
    message text,
    items_processed integer DEFAULT 0,
    items_success integer DEFAULT 0,
    items_failed integer DEFAULT 0,
    execution_time_ms integer,
    error_details jsonb,
    metadata jsonb DEFAULT '{}'::jsonb,
    started_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL,
    finished_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT timezone('utc'::text, now()) NOT NULL
);


--
-- Name: TABLE jobs_log; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON TABLE public.jobs_log IS 'Registro de ejecución de jobs automáticos y scraping';


--
-- Name: COLUMN jobs_log.job_type; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.jobs_log.job_type IS 'Tipo de job (scraping, image_optimization, cleanup, duplicate_detection)';


--
-- Name: COLUMN jobs_log.execution_time_ms; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.jobs_log.execution_time_ms IS 'Tiempo de ejecución en milisegundos';


--
-- Name: COLUMN jobs_log.error_details; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.jobs_log.error_details IS 'Detalles JSON de errores si los hay';


--
-- Name: jobs_stats; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.jobs_stats WITH (security_invoker='on') AS
 SELECT job_type,
    count(*) AS total_executions,
    sum(
        CASE
            WHEN ((status)::text = 'success'::text) THEN 1
            ELSE 0
        END) AS successful,
    sum(
        CASE
            WHEN ((status)::text = 'failed'::text) THEN 1
            ELSE 0
        END) AS failed,
    avg(execution_time_ms) AS avg_execution_time_ms,
    max(started_at) AS last_execution
   FROM public.jobs_log
  GROUP BY job_type;


