--

COMMENT ON COLUMN public.search_analytics.source IS 'Origen de la búsqueda: header, hero o page';


--
-- Name: popular_searches; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.popular_searches AS
 SELECT query,
    count(*) AS search_count,
    max(created_at) AS last_searched,
    count(DISTINCT session_id) AS unique_sessions
   FROM public.search_analytics
  WHERE (created_at > (now() - '30 days'::interval))
  GROUP BY query
  ORDER BY (count(*)) DESC
 LIMIT 100
  WITH NO DATA;


